sql:
SELECT note_text
FROM clinical_notes
WHERE note_text LIKE '%medications%';

SELECT COUNT(*) AS note_count
FROM clinical_notes
WHERE note_priority = 'Medium';

SELECT COUNT(*) AS completed_steps_count
FROM treatment_steps
WHERE status = 'completed';

SELECT step_description
FROM treatment_steps
WHERE step_id = 0;

external_knowledge:
- 'Active treatment steps' refers to the current or ongoing steps in a patient's treatment plan; 
- 'Transplant records' refer to clinical notes containing information about organ transplants; 
- 'Viewed in the past year' means the access date is within the last 365 days from the current date.

- Edited and left notes for more than one patient implies that the count of patients edited by the user should be greater than 1;
- Users can interact with patients through editing and leaving notes, which requires both 'edit' access and matching author_id with user_id;
- Average steps per patient is a measure of the complexity of treatment plans for each patient.

sql:
SELECT AVG(step_count) AS average_steps_per_plan
FROM (
  SELECT plan_id, COUNT(step_id) AS step_count
  FROM treatment_steps
  GROUP BY plan_id
) AS step_summary;
